import React, { useState, useEffect } from "react";
import "./Timesheet.css";

const projects = [
  "Website Redesign",
  "Mobile App Development",
  "Internal Systems",
  "Client Meetings",
];

const Timesheet = () => {

  /* --------------------
        WEEK HANDLING
  ----------------------*/
  const getStartOfWeek = (date) => {
    const d = new Date(date);
    const day = d.getDay();
    const diff = d.getDate() - (day === 0 ? 6 : day - 1);
    return new Date(d.setDate(diff));
  };

  const [currentWeekStart, setCurrentWeekStart] = useState(
    getStartOfWeek(new Date())
  );

  const generateWeek = (startDate) => {
    const days = ["Monday","Tuesday","Wednesday","Thursday","Friday","Saturday","Sunday"];

    return days.map((day, i) => {
      const d = new Date(startDate);
      d.setDate(d.getDate() + i);

      return {
        day,
        dateText: d.toLocaleDateString("en-US", { month: "short", day: "numeric" }),
        key: d.toISOString().split("T")[0],
        activities: []
      };
    });
  };

  /* --------------------
        STATE
  ----------------------*/
  const [entries, setEntries] = useState([]);
  const [status, setStatus] = useState("DRAFT");

  const weekKey = currentWeekStart.toISOString().split("T")[0];

  /* ------------------------------
      WHICH WEEK TO LOAD?
  ------------------------------*/
  useEffect(() => {
    const selected = localStorage.getItem("selected-week");

    if (selected) {
      setCurrentWeekStart(new Date(selected));
      localStorage.removeItem("selected-week");
    } else {
      setCurrentWeekStart(getStartOfWeek(new Date()));
    }
  }, []);


  /* ------------------------------
      LOAD WEEK DATA
  ------------------------------*/
  useEffect(() => {
    const saved = localStorage.getItem(weekKey);

    if (saved) {
      const parsed = JSON.parse(saved);

      let loaded = parsed.entries || generateWeek(currentWeekStart);

      // migrate old weekly system → new multi activities
      loaded = loaded.map(d =>
        d.activities
          ? d
          : {
              ...d,
              activities: d.project
                ? [{ project: d.project, hours: d.hours || 0, description: d.description || "" }]
                : []
            }
      );

      setEntries(loaded);
      setStatus(parsed.status || "DRAFT");
    } 
    else {
      setEntries(generateWeek(currentWeekStart));
      setStatus("DRAFT");
    }

  }, [currentWeekStart]);



  /* ------------------------------
      AUTO SAVE
  ------------------------------*/
  useEffect(() => {
    if (entries.length === 0) return;

    localStorage.setItem(
      weekKey,
      JSON.stringify({
        entries,
        status
      })
    );

  }, [entries, status, weekKey]);


  /* --------------------
        NAVIGATION
  ----------------------*/
  const changeWeek = (days) => {
    const newDate = new Date(currentWeekStart);
    newDate.setDate(newDate.getDate() + days);
    setCurrentWeekStart(getStartOfWeek(newDate));
  };


  /* --------------------
        ACTIVITY HANDLING
  ----------------------*/
  const addActivity = (dayIndex) => {
    if (status === "SUBMITTED") return;

    const updated = [...entries];
    updated[dayIndex].activities.push({
      project: "",
      hours: 0,
      description: ""
    });

    setEntries(updated);
  };

  const updateActivity = (dayIndex, actIndex, field, value) => {
    if (status === "SUBMITTED") return;

    const updated = [...entries];
    updated[dayIndex].activities[actIndex][field] = value;
    setEntries(updated);
  };

  const removeActivity = (dayIndex, actIndex) => {
    if (status === "SUBMITTED") return;

    const updated = [...entries];
    updated[dayIndex].activities.splice(actIndex, 1);
    setEntries(updated);
  };


  /* --------------------
        HOURS
  ----------------------*/
  const totalHours = entries.reduce((sum, day) =>
    sum + day.activities.reduce((s, a) => s + Number(a.hours || 0), 0)
  , 0);

  const overtime = totalHours > 40 ? totalHours - 40 : 0;



  /* -------------------------------------
        SAVE TO HISTORY (NO DUPLICATES)
  -------------------------------------*/
  const saveHistory = (newStatus) => {
    setStatus(newStatus);

    const weekRange = `${entries[0].dateText} - ${entries[6].dateText}`;
    let history = JSON.parse(localStorage.getItem("timesheet-history")) || [];

    const existingIndex = history.findIndex(h => h.key === weekKey);

    const record = {
      key: weekKey,
      weekRange,
      totalHours,
      status: newStatus,
      days: entries,
      timestamp: Date.now()
    };

    if (existingIndex !== -1) history[existingIndex] = record;
    else history.push(record);

    localStorage.setItem("timesheet-history", JSON.stringify(history));

    localStorage.setItem(
      weekKey,
      JSON.stringify({
        entries,
        status: newStatus
      })
    );
  };



  /* --------------------
        UI
  ----------------------*/
  return (
    <div className="timesheet-container">

      {/* SUMMARY */}
      <div className="summary">
        <div className="summary-box">
          <h4>Weekly Total</h4>
          <p>{totalHours} hours</p>
        </div>

        <div className="summary-box">
          <h4>Overtime</h4>
          <p>{overtime} hours</p>
        </div>

        <div className="summary-box">
          <h4>Status</h4>
          <p style={{ color: status === "SUBMITTED" ? "green" : "#2563eb" }}>
            {status}
          </p>
        </div>
      </div>


      {/* WEEK HEADER */}
      <div className="week-header">
        <button onClick={() => changeWeek(-7)}>{"< Previous"}</button>

        <h3>
          {entries.length > 0 &&
            `${entries[0].dateText} - ${entries[6].dateText}`
          }
        </h3>

        <button onClick={() => changeWeek(7)}>{"Next >"}</button>

        <button
          className="today-btn"
          onClick={() => setCurrentWeekStart(getStartOfWeek(new Date()))}
        >
          Today
        </button>
      </div>



      {/* TABLE */}
      <table>
        <thead>
          <tr>
            <th>Day</th>
            <th>Date</th>
            <th>Activities</th>
            <th>Total Day Hours</th>
          </tr>
        </thead>

        <tbody>
          {entries.map((day, dIndex) => {
            const dayHours = day.activities.reduce(
              (s, a) => s + Number(a.hours || 0),
              0
            );

            return (
              <tr key={day.key}>
                <td>{day.day}</td>
                <td>{day.dateText}</td>

                <td>
                  {day.activities.map((act, aIndex) => (
                    <div key={aIndex} className="activity-box">

                      <select
                        disabled={status === "SUBMITTED"}
                        value={act.project}
                        onChange={(e) =>
                          updateActivity(dIndex, aIndex, "project", e.target.value)
                        }
                      >
                        <option value="">Select Project</option>
                        {projects.map((p, i) => (
                          <option key={i} value={p}>{p}</option>
                        ))}
                      </select>

                      <input
                        disabled={status === "SUBMITTED"}
                        type="number"
                        min="0"
                        max="24"
                        value={act.hours}
                        onChange={(e) =>
                          updateActivity(dIndex, aIndex, "hours", e.target.value)
                        }
                      />

                      <textarea
                        disabled={status === "SUBMITTED"}
                        value={act.description}
                        onChange={(e) =>
                          updateActivity(dIndex, aIndex, "description", e.target.value)
                        }
                      />

                      <button
                        disabled={status === "SUBMITTED"}
                        className="remove-btn"
                        onClick={() => removeActivity(dIndex, aIndex)}
                      >
                        Remove
                      </button>
                    </div>
                  ))}

                  <button
                    disabled={status === "SUBMITTED"}
                    className="add-work-btn"
                    onClick={() => addActivity(dIndex)}
                  >
                    + Add Work Entry
                  </button>
                </td>

                <td>
                  <strong>{dayHours} hrs</strong>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>



      {/* FOOTER */}
      <div className="footer-section">
        <h3>Total Hours: {totalHours}</h3>

        <div className="action-buttons">
          <button
            disabled={status === "SUBMITTED"}
            onClick={() => saveHistory("DRAFT")}
          >
            Save as Draft
          </button>

          <button
            disabled={status === "SUBMITTED"}
            className="submit-btn"
            onClick={() => saveHistory("SUBMITTED")}
          >
            Submit Timesheet
          </button>
        </div>
      </div>
    </div>
  );
};

export default Timesheet;
